// ════════════════════════════════
// STATE
// ════════════════════════════════
let cart=[], curProd=null, dqty=1, discount=0;
let filters={cats:[],maxPrice:500};
let curPage=1; const PER_PAGE=12;

// ════════════════════════════════
// NAVIGATION
// ════════════════════════════════
// AFTER
function goPage(n, pushHistory = true){
  document.querySelectorAll('.page').forEach(p=>p.classList.remove('active'));
  document.getElementById('pg-'+n).classList.add('active');
  window.scrollTo(0,0);
  if(n==='shop') renderShop();
  if(n==='cart') renderCart();
  if(n==='home') initRv();

  // Push a new history entry so the browser back/forward buttons work
  if(pushHistory){
    const state = { page: n, prodId: n === 'detail' ? curProd?.id : null };
    history.pushState(state, '', '#' + n);
  }
}
function catGo(c){
  filters.cats=[c];
  curPage=1;
  document.querySelectorAll('#catFilters input').forEach(cb=>{cb.checked=cb.value===c;});
  goPage('shop');
}
function toReviews(){setTimeout(()=>document.getElementById('rev-anchor')?.scrollIntoView({behavior:'smooth'}),100);}

// ════════════════════════════════
// HELPERS
// ════════════════════════════════
function catClass(c){return'c-'+c.toLowerCase();}
function starStr(r){return'★'.repeat(r)+'☆'.repeat(5-r);}

// ════════════════════════════════
// SHOP FILTERS
// ════════════════════════════════
function buildCatFilters(){
  const cats=[...new Set(products.map(p=>p.cat))].sort();
  document.getElementById('catFilters').innerHTML=cats.map(c=>{
    const n=products.filter(p=>p.cat===c).length;
    return`<li class="fitem"><input type="checkbox" id="cf-${c}" value="${c}" onchange="onCatCb()"><label for="cf-${c}">${c}</label><span class="fc">(${n})</span></li>`;
  }).join('');
}
function onCatCb(){filters.cats=[...document.querySelectorAll('#catFilters input:checked')].map(cb=>cb.value);curPage=1;renderShop();}
function onPrice(v){filters.maxPrice=parseInt(v);document.getElementById('pDisp').textContent=`Up to $${parseFloat(v).toFixed(2)}`;curPage=1;renderShop();}
function clearF(){
  filters={cats:[],maxPrice:500};curPage=1;
  document.getElementById('priceSlider').value=200;
  document.getElementById('pDisp').textContent='Up to $200.00';
  document.querySelectorAll('#catFilters input,#r5,#r4,#fNew,#fSale,#fBest').forEach(cb=>cb.checked=false);
  renderShop();
}
function getFiltered(){
  let list=[...products];
  if(filters.cats.length) list=list.filter(p=>filters.cats.includes(p.cat));
  list=list.filter(p=>p.price<=filters.maxPrice);
  if(document.getElementById('r5')?.checked) list=list.filter(p=>p.rating===5);
  else if(document.getElementById('r4')?.checked) list=list.filter(p=>p.rating>=4);
  if(document.getElementById('fNew')?.checked) list=list.filter(p=>p.badge==='New');
  if(document.getElementById('fSale')?.checked) list=list.filter(p=>p.badge==='Sale');
  if(document.getElementById('fBest')?.checked) list=list.filter(p=>p.badge==='Bestseller');
  const s=document.getElementById('sortSel')?.value||'default';
  if(s==='price-asc') list.sort((a,b)=>a.price-b.price);
  else if(s==='price-desc') list.sort((a,b)=>b.price-a.price);
  else if(s==='rating') list.sort((a,b)=>b.rating-a.rating||b.reviews-a.reviews);
  else if(s==='newest') list.sort((a,b)=>b.newest-a.newest);
  return list;
}

function renderShop(){
  const all=getFiltered();
  const totalPages=Math.ceil(all.length/PER_PAGE);
  if(curPage>totalPages) curPage=Math.max(1,totalPages);
  const list=all.slice((curPage-1)*PER_PAGE,curPage*PER_PAGE);
  const g=document.getElementById('shopGrid');
  document.getElementById('rcount').innerHTML=`<strong>${all.length}</strong> product${all.length!==1?'s':''} found`;
  if(!all.length){g.innerHTML='';document.getElementById('noRes').style.display='block';document.getElementById('pgBar').innerHTML='';return;}
  document.getElementById('noRes').style.display='none';
  g.innerHTML=list.map(p=>cardHTML(p)).join('');
  renderPagination(totalPages);
}

function renderPagination(total){
  const bar=document.getElementById('pgBar');
  if(total<=1){bar.innerHTML='';return;}
  const atFirst=(curPage===1);
  const atLast=(curPage===total);
  let h=`<button class="pg-btn arrow${atFirst?' pg-disabled':''}" onclick="if(${curPage}>1)changePage(${curPage-1})">‹</button>`;
  for(let i=1;i<=total;i++){
    if(i===1||i===total||Math.abs(i-curPage)<=1){
      h+=`<button class="pg-btn${i===curPage?' active':''}" onclick="changePage(${i})">${i}</button>`;
    } else if(Math.abs(i-curPage)===2){
      h+=`<button class="pg-btn pg-dots">…</button>`;
    }
  }
  h+=`<button class="pg-btn arrow${atLast?' pg-disabled':''}" onclick="if(${curPage}<${total})changePage(${curPage+1})">›</button>`;
  bar.innerHTML=h;
}
function changePage(n){
  const all=getFiltered();
  const totalPages=Math.ceil(all.length/PER_PAGE);
  if(n<1||n>totalPages)return;
  curPage=n;
  renderShop();
  window.scrollTo({top:300,behavior:'smooth'});
}

// ════════════════════════════════
// CARD HTML
// ════════════════════════════════
function cardHTML(p,dark){
  const d=dark;
  const badge=p.badge?`<div class="pbadge${p.badge==='Sale'?' sale':p.badge==='New'?' new':''}">${p.badge}</div>`:'';
  const visual=p.imgSrc
    ?`<img class="pimg-photo" src="${p.imgSrc}" alt="${p.name}" loading="lazy" style="position:absolute;inset:0;width:100%;height:100%;object-fit:cover;object-position:center top;">`
    :`<span class="pimg-emoji">${p.emoji||''}</span>`;
  const subInfo=p.brand?`<div class="pcard-brand">${p.brand}</div><div class="pcard-notes">${p.notes}</div>`:'';
  const priceStr=p.priceDisplay||`$${p.price.toFixed(2)}`;
  return`<div class="pcard"${d?' style="background:#1a1a1a;border-color:rgba(201,168,76,0.1)"':''}>
    ${badge}
    <div class="pimg ${catClass(p.cat)}"${d?' style="background:linear-gradient(135deg,#2a2a2a,#1a1616)"':''}>
      ${visual}
      <div class="poverlay">
        <button class="oadd" onclick="addToCart(${p.id});event.stopPropagation()">Add to Cart</button>
        <button class="oview" onclick="openDetail(${p.id});event.stopPropagation()">View Details</button>
      </div>
    </div>
    <div class="pinfo" onclick="openDetail(${p.id})" style="cursor:pointer">
      <div class="pname"${d?' style="color:#fff"':''}>${p.name}</div>
      <div class="pcat"${d?' style="color:rgba(255,255,255,0.35)"':''}>${p.cat}</div>
      ${subInfo}
      <div class="pfoot">
        <div class="pprice"${d?' style="color:var(--gold-light)"':''}>${priceStr}</div>
        <div class="pstars">${starStr(p.rating)} <span style="font-size:0.58rem;color:${d?'rgba(255,255,255,0.3)':'rgba(42,42,42,0.4)'}">(${p.reviews})</span></div>
      </div>
    </div>
  </div>`;
}

// ════════════════════════════════
// PRODUCT DETAIL
// ════════════════════════════════
function openDetail(id){
  const p=products.find(x=>x.id===id); if(!p) return;
  curProd=p; dqty=1;
  document.getElementById('qnum').textContent=1;
  document.getElementById('dcrumb').textContent=p.name;
  document.getElementById('dcat').textContent=p.cat;
  document.getElementById('dname').textContent=p.name;
  document.getElementById('dstars').innerHTML=starStr(p.rating)+` <span>(${p.reviews} reviews)</span>`;
  document.getElementById('ddesc').innerHTML=p.brand
    ?`<div class="dperf-brand">${p.brand} &nbsp;·&nbsp; ${p.size||''}</div><p style="margin-top:0.8rem">${p.desc}</p><div class="dperf-notes">Notes: ${p.notes||''}</div>`
    :p.desc;
  document.getElementById('dprice').textContent=p.priceDisplay||`$${p.price.toFixed(2)}`;
  const di=document.getElementById('dimg');
  di.className=`dimg ${catClass(p.cat)}`;
  // Render image or emoji
  const demojiEl=document.getElementById('demoji');
  if(p.imgSrc){
    demojiEl.style.cssText='display:none';
    const existingImg=di.querySelector('img.dimg-photo');
    if(existingImg) existingImg.remove();
    const img=document.createElement('img');
    img.className='dimg-photo';
    img.src=p.imgSrc; img.alt=p.name;
    img.style.cssText='position:absolute;inset:0;width:100%;height:100%;object-fit:cover;object-position:center top;display:block;';
    di.appendChild(img);
  } else {
    demojiEl.style.cssText='';
    demojiEl.textContent=p.emoji||'';
    const existingImg=di.querySelector('img.dimg-photo');
    if(existingImg) existingImg.remove();
  }
  const b=document.getElementById('dbadge');
  if(p.badge){b.textContent=p.badge;b.className='dbadge'+(p.badge==='Sale'?' sale':'');b.style.display='block';}
  else b.style.display='none';
  // related
  const rel=products.filter(x=>x.cat===p.cat&&x.id!==p.id).slice(0,4);
  document.getElementById('relGrid').innerHTML=rel.map(x=>cardHTML(x)).join('');
  // Replace just the last line of openDetail:
  goPage('detail', false);
  history.pushState({ page: 'detail', prodId: p.id }, '', '#detail-' + p.id);;
}
function dq(d){dqty=Math.max(1,dqty+d);document.getElementById('qnum').textContent=dqty;}
function addCurrent(){
  if(!curProd) return;
  for(let i=0;i<dqty;i++) addToCart(curProd.id,false);
  showToast(`${dqty}× ${curProd.name} added ✦`);
  updateCount();
}

// ════════════════════════════════
// CART
// ════════════════════════════════
function addToCart(id,toast=true){
  const p=products.find(x=>x.id===id); if(!p) return;
  const ex=cart.find(c=>c.id===id);
  if(ex) ex.qty++; else cart.push({...p,qty:1});
  updateCount();
  if(toast) showToast(`${p.name} added ✦`);
}
function updateCount(){document.getElementById('cartCount').textContent=cart.reduce((s,c)=>s+c.qty,0);}
function renderCart(){
  const l=document.getElementById('cartList'),e=document.getElementById('emptyCart');
  if(!cart.length){l.innerHTML='';e.style.display='block';updateSummary();return;}
  e.style.display='none';
  l.innerHTML=cart.map(it=>`
    <div class="ci">
      <div class="ci-img ${catClass(it.cat)}">${it.imgSrc?`<img src="${it.imgSrc}" alt="${it.name}" style="width:100%;height:100%;object-fit:contain;">`:it.emoji||''}</div>
      <div>
        <div class="ci-name">${it.name}</div>
        <div class="ci-cat">${it.cat}</div>
        <div class="ci-price">$${it.price.toFixed(2)} each</div>
        <div class="qctrl" style="margin-top:0.8rem;display:inline-flex">
          <button class="qbtn" onclick="cqty(${it.id},-1)">−</button>
          <span class="qnum">${it.qty}</span>
          <button class="qbtn" onclick="cqty(${it.id},1)">+</button>
        </div>
      </div>
      <div class="ci-right">
        <div class="ci-total">$${(it.price*it.qty).toFixed(2)}</div>
        <button class="rm-btn" onclick="rmCart(${it.id})">Remove</button>
      </div>
    </div>`).join('');
  updateSummary();
}
function cqty(id,d){const it=cart.find(c=>c.id===id);if(!it) return;it.qty=Math.max(0,it.qty+d);if(it.qty===0) cart=cart.filter(c=>c.id!==id);updateCount();renderCart();}
function rmCart(id){cart=cart.filter(c=>c.id!==id);updateCount();renderCart();}
function updateSummary(){
  const sub=cart.reduce((s,c)=>s+c.price*c.qty,0);
  const ship=sub===0?0:sub>=50?0:5.99;
  const total=Math.max(0,sub+ship-discount);
  document.getElementById('oSub').textContent=`$${sub.toFixed(2)}`;
  document.getElementById('oShip').textContent=sub===0?'—':ship===0?'Free ✦':`$${ship.toFixed(2)}`;
  document.getElementById('oDisc').textContent=discount>0?`-$${discount.toFixed(2)}`:'—';
  document.getElementById('oTotal').textContent=`$${total.toFixed(2)}`;
}
function applyPromo(){
  const c=document.getElementById('promoIn').value.toUpperCase().trim();
  if(c==='IMANI10'){discount=cart.reduce((s,c)=>s+c.price*c.qty,0)*0.1;showToast('10% off applied! ✦');updateSummary();}
  else if(c==='QUEEN'){discount=5;showToast('$5 discount applied! ✦');updateSummary();}
  else showToast('Invalid promo code');
}
function checkout(){
  if(!cart.length) return;
  showToast('Processing order… ✦');
  setTimeout(()=>{cart=[];discount=0;updateCount();showToast('Order placed! Thank you, Queen ♡');renderCart();},2000);
}

