// ════════════════════════════════
// TOAST
// ════════════════════════════════
let tt;
function showToast(msg){
  const t=document.getElementById('toast');
  document.getElementById('toastMsg').textContent=msg;
  t.classList.add('show');
  clearTimeout(tt);
  tt=setTimeout(()=>t.classList.remove('show'),3000);
}

// ════════════════════════════════
// SCROLL REVEAL
// ════════════════════════════════
function initRv(){
  const obs=new IntersectionObserver(en=>en.forEach(e=>{if(e.isIntersecting)e.target.classList.add('vis');}),{threshold:0.1});
  document.querySelectorAll('.rv').forEach(el=>obs.observe(el));
}



// ════════════════════════════════
// MOBILE MENU
// ════════════════════════════════
function toggleMobMenu(){
  const btn=document.getElementById('mobMenuBtn');
  const menu=document.getElementById('mobMenu');
  btn.classList.toggle('open');
  menu.classList.toggle('open');
  document.body.style.overflow=menu.classList.contains('open')?'hidden':'';
}
function closeMobMenu(){
  document.getElementById('mobMenuBtn').classList.remove('open');
  document.getElementById('mobMenu').classList.remove('open');
  document.body.style.overflow='';
}

// ════════════════════════════════
// WHATSAPP
// ════════════════════════════════
// ⚠️  Replace with your actual WhatsApp number (include country code, no + or spaces)
const WA_NUMBER = '16467839583';

function openWaModal(){
  populateWaPreview();
  document.getElementById('waModalBg').classList.add('open');
  document.body.style.overflow='hidden';
}
function closeWaModal(){
  document.getElementById('waModalBg').classList.remove('open');
  document.body.style.overflow='';
}
function handleWaBgClick(e){
  if(e.target===document.getElementById('waModalBg')) closeWaModal();
}
function populateWaPreview(){
  const list=document.getElementById('waItemsList');
  const totalRow=document.getElementById('waTotalRow');
  if(!cart.length){
    list.innerHTML='<p style="font-size:0.78rem;color:rgba(42,42,42,0.4)">No items in cart yet. Add products first!</p>';
    totalRow.style.display='none';
    return;
  }
  list.innerHTML=cart.map(it=>`
    <div class="wa-item-row">
      <span>${it.emoji} ${it.name} × ${it.qty}</span>
      <span>$${(it.price*it.qty).toFixed(2)}</span>
    </div>`).join('');
  const sub=cart.reduce((s,c)=>s+c.price*c.qty,0);
  const ship=sub>=50?0:5.99;
  const total=Math.max(0,sub+ship-discount);
  document.getElementById('waTotal').textContent=`$${total.toFixed(2)}`;
  totalRow.style.display='flex';
}
function sendWhatsApp(){
  const name=document.getElementById('waName').value.trim();
  const phone=document.getElementById('waPhone').value.trim();
  const address=document.getElementById('waAddress').value.trim();
  const notes=document.getElementById('waNotes').value.trim();

  if(!name){showToast('Please enter your name');return;}
  if(!phone){showToast('Please enter your phone number');return;}
  if(!address){showToast('Please enter your delivery address');return;}
  if(!cart.length){showToast('Your cart is empty — add some products first!');return;}

  const sub=cart.reduce((s,c)=>s+c.price*c.qty,0);
  const ship=sub>=50?0:5.99;
  const total=Math.max(0,sub+ship-discount);

  let msg = `✨ *NEW ORDER — Imani's Beauty* ✨\n\n`;
  msg += `👤 *Customer:* ${name}\n`;
  msg += `📞 *Phone:* ${phone}\n`;
  msg += `📍 *Address:* ${address}\n`;
  if(notes) msg += `📝 *Notes:* ${notes}\n`;
  msg += `\n🛍️ *ORDER ITEMS:*\n`;
  cart.forEach(it=>{
    msg += `• ${it.imgSrc?"🌸":it.emoji||"✦"} ${it.name} × ${it.qty} = $${(it.price*it.qty).toFixed(2)}\n`;
  });
  msg += `\n💰 *Subtotal:* $${sub.toFixed(2)}\n`;
  msg += `🚚 *Shipping:* ${ship===0?'Free':'$'+ship.toFixed(2)}\n`;
  if(discount>0) msg += `🎉 *Discount:* -$${discount.toFixed(2)}\n`;
  msg += `💛 *TOTAL: $${total.toFixed(2)}*\n\n`;
  msg += `Please confirm my order. Thank you! 🙏`;

  const url=`https://wa.me/${WA_NUMBER}?text=${encodeURIComponent(msg)}`;
  window.open(url,'_blank');
  closeWaModal();
  showToast('Opening WhatsApp… 💛');
}

// ════════════════════════════════
// INIT
// ════════════════════════════════
document.addEventListener("DOMContentLoaded", () => {
  buildCatFilters();
  renderHome();
  initRv();
});

window.addEventListener('DOMContentLoaded', () => {
    renderShop(); 
    updateCartCount();
});

window.addEventListener('popstate', (e) => {
  const state = e.state;
  if(!state){
    goPage('home', false);
    return;
  }
  if(state.page === 'detail' && state.prodId){
    openDetail(state.prodId);
    // Prevent double push — override last line
    history.replaceState(state, '', location.hash);
  } else {
    goPage(state.page, false);
  }
});

// On load, check hash
const hash = location.hash.replace('#','');
if(hash.startsWith('detail-')){
  const id = parseInt(hash.replace('detail-',''));
  if(id) openDetail(id);
} else if(['shop','cart','about'].includes(hash)){
  goPage(hash, false);
} else {
  goPage('home', false); // default — replaces the initial renderHome() call
}